<?php declare(strict_types=1);require __DIR__.'/bootstrap.php';$pageTitle='Downloads';require VP3_ROOT.'/includes/account-header.php';$rows=[];if(vp3_db_available()){$stmt=vp3_db()->prepare("SELECT p.name,r.version,r.release_channel,r.release_notes,r.published_at,l.updates_until FROM licenses l JOIN products p ON p.id=l.product_id JOIN product_releases r ON r.product_id=p.id WHERE l.customer_id=? AND l.status='active' AND r.status='published' AND (l.updates_until IS NULL OR l.updates_until>=CURDATE()) ORDER BY r.published_at DESC");$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();}?><h1>Eligible product downloads</h1><p class="helper">Download delivery should use short-lived signed URLs in production. Foundation v1 intentionally does not expose raw artifact paths.</p><div class="table-wrap"><table class="table"><thead><tr><th>Product</th><th>Version</th><th>Channel</th><th>Published</th><th>Action</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=vp3_e($r['name'])?></td><td><?=vp3_e($r['version'])?></td><td><?=vp3_e($r['release_channel'])?></td><td><?=vp3_e($r['published_at'])?></td><td><span class="badge">Signed download pending</span></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="5">No eligible releases are available.</td></tr><?php endif;?></tbody></table></div><?php require VP3_ROOT.'/includes/account-footer.php';?>